-- Industry-level category structure and mapping
-- Generated: 2026-02-17T16:07:11.030Z

-- Note: This SQL mirrors the applied restructure.
-- If rerun, it keeps only the section_ids listed below enabled.

BEGIN;

ON CONFLICT (section_id) DO UPDATE SET
 title_en=EXCLUDED.title_en,title_te=EXCLUDED.title_te,subtitle_en=EXCLUDED.subtitle_en,subtitle_te=EXCLUDED.subtitle_te,description_en=EXCLUDED.description_en,description_te=EXCLUDED.description_te,display_order=EXCLUDED.display_order,is_enabled=EXCLUDED.is_enabled,updated_at=NOW();

UPDATE public.sections SET is_enabled=FALSE, updated_at=NOW()
WHERE section_id NOT IN ('soaps-body-bars','carrier-oils','butters-lipids','waxes-emulsifiers','surfactants-cleansers','humectants-actives','hydrosols-waters-liquids','bases-ready-mixes','essential-oils','starches-flours','clays-minerals','herbal-powders-skin','herbal-powders-hair');

-- For full product mapping SQL, keep using scripts/restructure-industry-categories.js (already applied).
COMMIT;
